div.style:
position:fixed; bottom:24px; right:24px; z-index:9999;
background:#0c4a6e; color:#fff; border-radius:12px;
padding:12px 18px; font-size:13px; font-weight:600;
display:flex; align-items:center; gap:10px;
box-shadow:0 8px 32px rgba(10,40,70,.35);
transform:translateY(80px); opacity:0;
transition:transform 0.35s cubic-bezier(.22,1,.36,1), opacity 0.3s;
pointer-events:none;

t.script:
//
document.addEventListener('DOMContentLoaded', function () {

    // ── COLUMN COUNTS ─────────────────────────────────────
    function refreshCounts() {
        ['new', 'in_progress', 'resolved', 'closed'].forEach(function (state) {
            var col     = document.getElementById('col-' + state);
            var countEl = document.getElementById('count-' + state);
            if (col && countEl) {
                countEl.textContent = col.querySelectorAll('.kanban-card').length;
            }
        });
    }
    refreshCounts();

    // ── CARD CLICKS → open modal ─────────────────────────
    function bindCardClicks() {
        document.querySelectorAll('.kanban-card').forEach(function (card) {
            if (card._clickBound) return;
            card._clickBound = true;
            card.addEventListener('click', function () {
                var id = this.getAttribute('data-ticket-id');
                if (id) openTicketModal(id);
            });
        });
    }
    bindCardClicks();

    // ── TOGGLE BUTTONS ────────────────────────────────────
    document.getElementById('listViewBtn').addEventListener('click', function () {
        window.location.href = '/customer_support/tickets';
    });
    document.getElementById('kanbanViewBtn').addEventListener('click', function () {
        window.location.href = '/customer_support/tickets/kanban';
    });

    // ── COLUMN MAP: which DOM column each state belongs to ─
    var STATE_COL = {
        'new':         'col-new',
        'assigned':    'col-in_progress',
        'in_progress': 'col-in_progress',
        'pending':     'col-in_progress',
        'resolved':    'col-resolved',
        'closed':      'col-closed',
    };

    // ── TOAST helper ──────────────────────────────────────
    var _toastTimer = null;
    function showToast(msg) {
        var t = document.getElementById('kpToast');
        document.getElementById('kpToastMsg').textContent = msg;
        t.style.transform = 'translateY(0)';
        t.style.opacity   = '1';
        clearTimeout(_toastTimer);
        _toastTimer = setTimeout(function () {
            t.style.transform = 'translateY(80px)';
            t.style.opacity   = '0';
        }, 4000);
    }

    // ── POLLING ───────────────────────────────────────────
    function pollStates() {
        fetch('/customer_support/tickets/states', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ jsonrpc:'2.0', method:'call', id:1, params:{} })
        })
        .then(function(r) { return r.json(); })
        .then(function(resp) {
            var data = (resp.result || {});
            if (!data.success) return;
            var states = data.states || {};
            var changed = 0;

            Object.keys(states).forEach(function(ticketId) {
                var newState = states[ticketId].state;
                var label    = states[ticketId].label;
                var card     = document.querySelector('.kanban-card[data-ticket-id="' + ticketId + '"]');
                if (!card) return;

                var targetColId = STATE_COL[newState];
                var targetCol   = targetColId ? document.getElementById(targetColId) : null;
                if (!targetCol) return;

                // Check if card is already in the right column
                if (targetCol.contains(card)) return;

                // Animate out, move, animate in
                card.style.transition = 'opacity 0.3s, transform 0.3s';
                card.style.opacity    = '0';
                card.style.transform  = 'scale(0.92)';
                setTimeout(function () {
                    targetCol.appendChild(card);
                    card.style.opacity   = '1';
                    card.style.transform = 'scale(1)';
                    setTimeout(function() {
                        card.style.transition = '';
                        card.style.transform  = '';
                    }, 350);
                    // Update state badge inside modal if it's open for this ticket
                    var sb = document.getElementById('tdmStateBadge');
                    var tn = document.getElementById('tdmTicketNum');
                    if (sb && tn && tn.textContent) {
                        // Find current open ticket id from modal
                        var openCard = document.querySelector('.kanban-card._modal-open');
                        if (openCard && openCard.getAttribute('data-ticket-id') === ticketId) {
                            sb.textContent = label;
                            sb.className   = 'tdm-state-badge tdm-state-' + newState;
                        }
                    }
                    refreshCounts();
                    bindCardClicks();
                }, 320);
                changed++;
            });

            if (changed > 0) {
                showToast(changed === 1
                    ? '1 ticket status was updated'
                    : changed + ' ticket statuses were updated');
            }
        })
        .catch(function() { /* silent fail */ });
    }

    // Poll every 30 seconds
    setInterval(pollStates, 30000);

});
//

    //
(function () {
    var bell      = document.getElementById('kanbanNotifBell');
    var dropdown  = document.getElementById('kanbanNotifDropdown');
    var badge     = document.getElementById('kanbanNotifBadge');
    var notifList = document.getElementById('kanbanNotifList');
    if (bell && dropdown) {
        bell.addEventListener('click', function (e) { e.stopPropagation(); dropdown.classList.toggle('open'); });
        document.addEventListener('click', function () { dropdown.classList.remove('open'); });
        dropdown.addEventListener('click', function (e) { e.stopPropagation(); });
    }
    var markReadBtn = document.getElementById('kanbanMarkRead');
    if (markReadBtn) {
        markReadBtn.addEventListener('click', function () {
            fetch('/customer_support/customer/notifications/mark_read', { method: 'POST', credentials: 'same-origin', headers: { 'Accept': 'application/json' } })
            .then(function () {
                if (badge) { badge.classList.add('d-none'); badge.textContent = '0'; }
                if (notifList) { notifList.innerHTML = '<div class="notif-empty"><i class="bi bi-check-circle-fill" style="font-size:2rem;color:#22c55e;display:block;margin-bottom:.5rem;"></i>All caught up!</div>'; }
            });
        });
    }
    function sanitise(str) { var d = document.createElement('div'); d.textContent = String(str || ''); return d.innerHTML; }
    function renderNotifications(items) {
        if (!notifList) return;
        if (!items || !items.length) {
            notifList.innerHTML = '<div class="notif-empty"><i class="bi bi-check-circle-fill" style="font-size:2rem;color:#22c55e;display:block;margin-bottom:.5rem;"></i>No new notifications</div>';
            if (badge) badge.classList.add('d-none');
            return;
        }
        if (badge) { badge.textContent = items.length; badge.classList.remove('d-none'); }
        var typeLabels = { status_change: 'Status Update', assigned: 'Assigned', sla_breach: 'SLA Breach' };
        notifList.innerHTML = items.map(function (n) {
            var cls        = sanitise(n.cls   || 'status');
            var icon       = sanitise(n.icon  || 'bi-bell-fill');
            var ticketName = sanitise(n.ticket_name || (n.ticket_id ? '#' + n.ticket_id : ''));
            var typeLabel  = sanitise(typeLabels[n.type] || 'Notification');
            var msg        = sanitise(n.message || '');
            var time       = sanitise(n.time   || '');
            var title      = ticketName ? ticketName + ' \u00b7 ' + typeLabel : typeLabel;
            return '<div class="notif-item">'
                + '<div class="notif-icon-wrap ' + cls + '"><i class="bi ' + icon + '"></i></div>'
                + '<div class="notif-body">'
                + '<div class="notif-title">' + title + '</div>'
                + '<div class="notif-sub">' + msg + '</div>'
                + '<div class="notif-time-text">' + time + '</div>'
                + '</div>'
                + '<div class="notif-dot ' + cls + '"></div>'
                + '</div>';
        }).join('');
    }
    function loadNotifications() {
        fetch('/customer_support/customer/notifications', { method: 'GET', credentials: 'same-origin', headers: { 'Accept': 'application/json' } })
        .then(function (r) { return r.json(); })
        .then(function (data) { renderNotifications(data.notifications || []); })
        .catch(function () { renderNotifications([]); });
    }
    loadNotifications();
    setInterval(loadNotifications, 30000);
})();
//

//
(function () {
    var overlay  = document.getElementById('ticketModal');
    var panel    = overlay ? overlay.querySelector('.tdm-panel') : null;
    var loading  = document.getElementById('tdmLoading');
    var content  = document.getElementById('tdmContent');
    var currentTicketId = null;
    var csrf     = (document.cookie.match(/\bsession_id=([^;]+)/) || [])[1] || '';

    function escHtml(s) {
        return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    }

    function stripHtml(s) {
        var d = document.createElement('div');
        d.innerHTML = String(s || '');
        return (d.textContent || d.innerText || '').trim();
    }

    function renderMessages(items) {
        var host = document.getElementById('tdmMessages');
        if (!host) return;
        if (!items || !items.length) {
            host.innerHTML = '<div class="tdm-msg-empty">No messages yet.</div>';
            return;
        }
        host.innerHTML = items.map(function (m) {
            var mine = m.is_me ? ' mine' : '';
            return '<div class="tdm-msg-row' + mine + '">'
                + '<div class="tdm-msg-bubble">'
                + '<div class="tdm-msg-head"><span class="tdm-msg-author">' + escHtml(m.is_me ? 'You' : (m.author || 'Support')) + '</span><span class="tdm-msg-time">' + escHtml(m.date || '') + '</span></div>'
                + '<div class="tdm-msg-body">' + escHtml(stripHtml(m.body || '')) + '</div>'
                + '</div>'
                + '</div>';
        }).join('');
        host.scrollTop = host.scrollHeight;
    }

    function openTicketModal(ticketId) {
        currentTicketId = ticketId;
        overlay.style.display = 'flex';
        document.body.style.overflow = 'hidden';
        loading.style.display = 'flex';
        content.style.display = 'none';
        var ri = document.getElementById('tdmReplyInput');
        if (ri) ri.value = '';

        fetch('/customer_support/customer/ticket/' + ticketId + '/data', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ jsonrpc:'2.0', method:'call', id:1, params:{} })
        })
        .then(function(r){ return r.json(); })
        .then(function(resp) {
            var data = resp.result || {};
            if (!data.success) {
                loading.innerHTML = '<i class="bi bi-exclamation-circle" style="font-size:1.5rem;color:#ef4444"></i><span>' + escHtml(data.error||'Failed to load') + '</span>';
                return;
            }
            fillModal(data);
            loading.style.display = 'none';
            content.style.display = '';
        })
        .catch(function(e) {
            loading.innerHTML = '<i class="bi bi-wifi-off" style="font-size:1.5rem;color:#ef4444"></i><span>Network error</span>';
        });
    }

    function fillModal(data) {
        var t = data.ticket;
        document.getElementById('tdmTicketNum').textContent = t.name;
        var sb = document.getElementById('tdmStateBadge');
        sb.textContent = t.state_label;
        sb.className = 'tdm-state-badge tdm-state-' + t.state;
        var pb = document.getElementById('tdmPriBadge');
        pb.textContent = t.priority.charAt(0).toUpperCase() + t.priority.slice(1);
        pb.className = 'tdm-pri-badge tdm-pri-' + t.priority;

        document.getElementById('tdmSubject').textContent = t.subject;
        document.getElementById('tdmAssigned').textContent = t.assigned_to;
        document.getElementById('tdmCreated').textContent = t.created;

        var slaWrap = document.getElementById('tdmSlaWrap');
        if (t.sla_deadline) {
            slaWrap.style.display = 'flex';
            slaWrap.className = 'tdm-meta-item tdm-sla-' + t.sla_status;
            document.getElementById('tdmSla').textContent = 'SLA: ' + t.sla_deadline;
        } else {
            slaWrap.style.display = 'none';
        }

        document.getElementById('tdmDescription').textContent = t.description || 'No description provided.';

        // Board progress
        var boardSec = document.getElementById('tdmBoardSection');
        if (data.board_total > 0) {
            boardSec.style.display = '';
            var pct = data.board_progress;
            document.getElementById('tdmProgressPct').textContent = data.board_done + '/' + data.board_total + ' · ' + pct + '%';
            var fill = document.getElementById('tdmProgressFill');
            fill.style.width = pct + '%';
            fill.className = 'tdm-progress-fill' + (pct === 100 ? ' done' : '');

            var colsHtml = '';
            (data.board_columns || []).forEach(function(col) {
                colsHtml += '<div class="tdm-col">';
                colsHtml += '<div class="tdm-col-head" style="border-left:3px solid ' + escHtml(col.color) + '">';
                colsHtml += '<span class="tdm-col-name">' + escHtml(col.name) + '</span>';
                colsHtml += '<span class="tdm-col-count">' + col.done_count + '/' + col.task_count + '</span>';
                colsHtml += '</div>';
                if (col.tasks && col.tasks.length) {
                    colsHtml += '<div class="tdm-col-tasks">';
                    col.tasks.forEach(function(task) {
                        var done = task.is_done;
                        colsHtml += '<div class="tdm-task' + (done ? ' tdm-task-done' : '') + '">';
                        colsHtml += '<i class="bi ' + (done ? 'bi-check-circle-fill' : 'bi-circle') + '"></i>';
                        colsHtml += '<span class="tdm-task-name">' + escHtml(task.name) + '</span>';
                        colsHtml += '</div>';
                    });
                    colsHtml += '</div>';
                } else {
                    colsHtml += '<div class="tdm-col-empty">No tasks</div>';
                }
                colsHtml += '</div>';
            });
            document.getElementById('tdmCols').innerHTML = colsHtml;
        } else {
            boardSec.style.display = 'none';
        }

        renderMessages(data.messages || []);
    }

    function closeModal() {
        overlay.style.display = 'none';
        document.body.style.overflow = '';
    }

    // Expose globally for inline handlers
    window.openTicketModal = openTicketModal;

    var sendBtn = document.getElementById('tdmReplySend');
    var replyInput = document.getElementById('tdmReplyInput');
    if (sendBtn && replyInput) {
        sendBtn.addEventListener('click', function () {
            var msg = (replyInput.value || '').trim();
            if (!currentTicketId || !msg) return;
            sendBtn.disabled = true;
            fetch('/customer_support/customer/ticket/' + currentTicketId + '/message/add', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ jsonrpc: '2.0', method: 'call', id: 1, params: { message: msg } })
            })
            .then(function (r) { return r.json(); })
            .then(function (resp) {
                var d = resp.result || {};
                if (!d.success) return;
                replyInput.value = '';
                return fetch('/customer_support/customer/ticket/' + currentTicketId + '/data', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ jsonrpc: '2.0', method: 'call', id: 1, params: {} })
                }).then(function (r) { return r.json(); }).then(function (ref) {
                    var rd = ref.result || {};
                    if (rd.success) fillModal(rd);
                });
            })
            .finally(function () { sendBtn.disabled = false; });
        });
    }

    document.getElementById('tdmClose').addEventListener('click', closeModal);
    document.getElementById('tdmCloseBtn').addEventListener('click', closeModal);
    overlay.addEventListener('click', function(e) {
        if (e.target === overlay) closeModal();
    });
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape') closeModal();
    });
})();
// bfcache guard
window.addEventListener('pageshow', function (e) {
    if (e.persisted) { window.location.reload(); }
});
// popstate guard: if back/forward navigates outside the portal, redirect to dashboard
window.addEventListener('popstate', function () {
    if (!window.location.pathname.startsWith('/customer_support/')) {
        window.location.replace('/customer_support/dashboard');
    }
});
